const http = require('http');
const fs = require('fs');

const E = (typeof process !== 'undefined' && process.env) ? process.env : {};
const zOrigin  = E.NUXT_ZITADEL_INTERNAL_URL || 'http://zitadel:8080';
const zHost    = (E.NUXT_ZITADEL_ISSUER || 'http://localhost:8200').replace(/^https?:\/\//, '');
const authBase = E.NUXT_PUBLIC_AUTH_APP_URL || 'http://localhost:4000/auth';

const body = $('Webhook').first().json.body || {};
const displayName = (body.displayName || '').trim();
const email = (body.email || '').trim();
const tenantId = body.tenantId || null;
const profileId = body.profileId || null;
if (!email || !tenantId) throw new Error('invite-user: email and tenantId are required');

const pat = fs.readFileSync('/zitadel-seed/admin.pat', 'utf8').trim();
if (!pat) throw new Error('invite-user: PAT file is empty');

function parseOrigin(o) {
  const n = String(o).replace(/^https?:\/\//, '');
  const i = n.indexOf(':');
  return i < 0 ? { host: n, port: '80' } : { host: n.slice(0, i), port: n.slice(i + 1) };
}
function httpReq(origin, path, method, headers, payload) {
  const { host, port } = parseOrigin(origin);
  return new Promise((resolve, reject) => {
    const r = http.request({ hostname: host, port, path, method, headers }, (res) => {
      let d = '';
      res.on('data', (c) => (d += c));
      res.on('end', () => { let j = null; try { j = d ? JSON.parse(d) : null; } catch { j = { raw: d }; } resolve({ status: res.statusCode, json: j }); });
    });
    r.on('error', reject);
    if (payload) r.write(payload);
    r.end();
  });
}
function zitadel(method, path, obj) {
  const payload = obj === undefined ? null : JSON.stringify(obj);
  const headers = { host: zHost, authorization: 'Bearer ' + pat, 'content-type': 'application/json' };
  if (payload) headers['content-length'] = Buffer.byteLength(payload);
  return httpReq(zOrigin, path, method, headers, payload);
}

const me = await zitadel('GET', '/management/v1/orgs/me');
const orgId = me.json && me.json.org && me.json.org.id;
if (!orgId) throw new Error('invite-user: orgs/me failed (' + me.status + ')');

const parts = displayName.split(' ').filter(Boolean);
const givenName = parts[0] || displayName || email;
const familyName = parts.slice(1).join(' ') || displayName || email;

const create = await zitadel('POST', '/v2/users/human', {
  username: email, organization: { orgId }, profile: { givenName, familyName }, email: { email, returnCode: {} },
});

let templateKey, vars, userId, subject;
const conflict = create.status === 409 || (create.status === 400 && /already exists/i.test(JSON.stringify(create.json || '')));
if (create.status === 200 || create.status === 201) {
  userId = create.json.userId;
  const emailCode = create.json.emailCode;
  const verifyUrl = authBase + '/verify-email?userId=' + encodeURIComponent(userId) + '&code=' + encodeURIComponent(emailCode);
  templateKey = 'user-invitation'; subject = 'You have been invited to fnb'; vars = { displayName: displayName || email, verifyUrl };
} else if (conflict) {
  // Re-invite: an unchanged email cannot be re-issued an email-verify code (confirmed 2026-07-22),
  // so mint a fresh password_reset link (email #2) instead — always works for an existing user.
  const search = await zitadel('POST', '/v2/users', { queries: [{ emailQuery: { emailAddress: email } }] });
  userId = search.json && search.json.result && search.json.result[0] && search.json.result[0].userId;
  if (!userId) throw new Error('invite-user re-invite: no ZITADEL user found for ' + email);
  const reset = await zitadel('POST', '/v2/users/' + encodeURIComponent(userId) + '/password_reset', { returnCode: {} });
  const resetCode = reset.json && reset.json.verificationCode;
  if (!resetCode) throw new Error('invite-user re-invite: password_reset failed (' + reset.status + ')');
  const setPasswordUrl = authBase + '/set-password?userId=' + encodeURIComponent(userId) + '&code=' + encodeURIComponent(resetCode);
  templateKey = 'set-password'; subject = 'Set your fnb password'; vars = { displayName: displayName || email, setPasswordUrl };
} else {
  throw new Error('invite-user: ZITADEL create user failed (' + create.status + '): ' + JSON.stringify(create.json));
}

// Output = the exact send-notification payload; the downstream HTTP Request node POSTs it with the
// fnb-webhook-secret credential.
return [{ json: { channel: 'email', templateKey, to: email, subject, vars, tenantId, profileId, userId } }];
